SELECT id AS chunk_id, kb_id, doc_id, content, metadata::text AS metadata, embedding <-> #{vectorLiteral}::vector AS distance, ROW_NUMBER() OVER (ORDER BY embedding <-> #{vectorLiteral}::vector) AS rank FROM chunk_bge_m3 WHERE
AND metadata->>'sourceName' = #{sourceName}
AND metadata->>'sourceType' = #{sourceType}
AND lower(regexp_replace(trim(COALESCE(metadata->>'contentPath', '')), '\s+', ' ', 'g')) LIKE CONCAT(#{contentPathPrefix}, '%')
ORDER BY embedding <-> #{vectorLiteral}::vector LIMIT #{limit}

SELECT id AS chunk_id, kb_id, doc_id, content, metadata::text AS metadata, embedding <-> #{vectorLiteral}::vector AS distance, ROW_NUMBER() OVER (ORDER BY embedding <-> #{vectorLiteral}::vector, created_at ASC, id ASC) AS rank FROM chunk_bge_m3 WHERE
AND lower(regexp_replace(trim(COALESCE(metadata->>'retrievableTitle', metadata->>'title')), '\s+', ' ', 'g')) = #{normalizedTitle}
AND metadata->>'sourceName' = #{sourceName}
AND metadata->>'sourceType' = #{sourceType}
AND lower(regexp_replace(trim(COALESCE(metadata->>'contentPath', '')), '\s+', ' ', 'g')) LIKE CONCAT(#{contentPathPrefix}, '%')
ORDER BY embedding <-> #{vectorLiteral}::vector, created_at ASC, id ASC LIMIT #{limit}

SELECT chunk_id, kb_id, doc_id, content, metadata, distance, rank FROM ( SELECT id AS chunk_id, kb_id, doc_id, content, metadata::text AS metadata, 2::double precision AS distance, ROW_NUMBER() OVER ( ORDER BY keyword_hit_count DESC, keyword_length_sum DESC, ABS(char_length(normalized_title) - #{queryLength}) ASC, char_length(normalized_title) ASC, created_at ASC, id ASC ) AS rank FROM ( SELECT id, kb_id, doc_id, content, metadata, created_at, lower(regexp_replace(trim(COALESCE(metadata->>'retrievableTitle', metadata->>'title')), '\s+', ' ', 'g')) AS normalized_title, ( SELECT COUNT(*) FROM ( SELECT DISTINCT keyword FROM (
SELECT #{keyword} AS keyword
) keyword_list WHERE lower(regexp_replace(trim(COALESCE(metadata->>'retrievableTitle', metadata->>'title')), '\s+', ' ', 'g')) LIKE CONCAT('%', keyword, '%') ) hit_keywords ) AS keyword_hit_count, ( SELECT COALESCE(SUM(char_length(keyword)), 0) FROM ( SELECT DISTINCT keyword FROM (
SELECT #{keyword} AS keyword
) keyword_list WHERE lower(regexp_replace(trim(COALESCE(metadata->>'retrievableTitle', metadata->>'title')), '\s+', ' ', 'g')) LIKE CONCAT('%', keyword, '%') ) hit_keywords ) AS keyword_length_sum FROM chunk_bge_m3 WHERE
) t WHERE keyword_hit_count > 0 ) ranked ORDER BY rank ASC LIMIT #{limit}
